   361	 * Intended for save-time validation. Catalog edits that would
   362	 * introduce a cycle should be rejected by calling this with the
   363	 * proposed catalog state.
   364	 */
   365	export function detectFamilyCycle(
   366	  rootFamilyId: string,
   367	  catalog: FamilyCatalogLookup,
   368	): string[] | null {
   369	  type Step = { id: string; path: string[] };
   370	  const queue: Step[] = [{ id: rootFamilyId, path: [rootFamilyId] }];
   371	  while (queue.length > 0) {
   372	    const { id, path } = queue.shift()!;
   373	    if (path.length > MAX_NESTED_FAMILY_DEPTH) {
   374	      throw new Error(
   375	        `FAM-01: family graph depth exceeds ${MAX_NESTED_FAMILY_DEPTH} for root '${rootFamilyId}'`,
   376	      );
